import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import DoctorRegisterStep1 from './pages/doctor_signup/doctor_signup_1';
import DoctorRegisterStep2 from './pages/doctor_signup/doctor_signup_2';
import DoctorLogin from './pages/doctor/DoctorLogin';

function App() {
    return (
        <BrowserRouter>
            <Routes>
                {/* Doctor Registration Flow */}
                <Route path="/doctor/register/step1" element={<DoctorRegisterStep1 />} />
                <Route path="/doctor/register/step2" element={<DoctorRegisterStep2 />} />
                <Route path="/doctor/login" element={<DoctorLogin />} />

                {/* Add other routes */}
            </Routes>
        </BrowserRouter>
    );
}

export default App;
